+                return rmw_ret;
+            }
+            // Setup cleanup function, in case of failure below
+            auto fail_cleanup = [&service_names_and_types]() {
+                                    rmw_ret_t rmw_ret = rmw_names_and_types_fini(service_names_and_types);
+                                    if (rmw_ret != RMW_RET_OK) {
